{
  "EmailBody": " New-MES: ad01d3de-58ca-41ca-ac60-d7b9dd88918c : CRITICAL - MCU MSSQL Server - Expensive Queries  , <html><head>\r\n<meta http-equiv=\"Content-Type\" content=\"text/html; charset=utf-8\"></head><body style=\"font-size:14px; font-family:helvetica,arial,sans-serif; padding:20px 0; margin:0; color:#333\"><div style=\"background-color:#FFCDD7; display:inline-block; padding:5px 10px; font-size:11pt; line-height:14pt; font-family:Aptos; text-align:left; margin-bottom:2pt; margin-left:2pt; border-radius:5px; border-left:10px solid #E51A92\">This message is from an external sender. Be cautious, especially with links and attachments, and report suspicious messages. </div><div><div style=\"margin:0 20px\">Impacted Service: MCU MSSQL Server<br>Impacted Entity: set @LocationOut=( <br><br><br>SELECT DISTINCT TOP 1 <br>CASE <br>WHEN RS.FromLocationID IS NOT NULL THEN(Select Distinct WL.location from inventory2 SI2 <br>join WAREHOUSE_LOCATION WL ON SI2.WarehouseLocationId=WL.ID <br>LEFT JOIN WAREHOUSE_LOCATION_CLASS WLC ON WL.WarehouseLocationClassID=WLC.ID AND WLC.Name NOT IN (Consignment,Subcontracting) <br>where WL.ID=RS.FromLocationID <br>AND SI2.QuantityOnHand &gt; 0 <br>AND SI2.ProductID=RSC.ProductID <br>AND SI2.InventoryStatus=1 <br>-- AND WLC.Name NOT IN (Consignment,Subcontracting) <br>AND WL.WarehouseLocationType = 2 <br>AND WL.ID!=@ToLocationID) -- Warehouse Location Type = Available <br><br>WHEN RS.FromLocationID IS NULL AND RS.FromZone IS NOT NULL <br>THEN (select Top 1 WL.Location FROM INVENTORY2 SI2 <br>JOIN WAREHOUSE_LOCATION WL ON SI2.WarehouseLocationID = WL.ID <br>JOIN CONTAINER C ON C.WarehouseLocationID = WL.ID <br>JOIN CONTAINER_CLASS CC ON C.ContainerClassID = CC.ID <br>left JOIN WAREHOUSE_LOCATION_CLASS WLC ON WL.WarehouseLocationClassID=WLC.ID AND WLC.Name NOT IN (Consignment,Subcontracting) <br>where WL.Zone=RS.FromZone <br>AND SI2.QuantityOnHand &gt; 0 <br>AND SI2.ProductID=RSC.ProductID <br>AND CC.Name IN (UC, UCX, Virtual) <br>AND WL.WarehouseLocationType = 2 -- Warehouse Location Type = Available <br>AND SI2.InventoryStatus=1 <br>--AND WLC.Name NOT IN (Consignment,Subcontracting) <br>AND WL.ID!=@ToLocationID <br>order by --C.createdon --Commented for CHG00005652 <br>SI2.CreatedOn --CHG00005652 <br>) <br><br>WHEN FromLocationID IS NULL AND FromZone IS NULL AND FromWarehouse IS NOT NULL <br>THEN (select top 1 WL.Location FROM INVENTORY2 SI2 <br>JOIN WAREHOUSE_LOCATION WL ON SI2.WarehouseLocationID = WL.ID <br>JOIN CONTAINER C ON C.WarehouseLocationID = WL.ID <br>JOIN CONTAINER_CLASS CC ON C.ContainerClassID = CC.ID <br>LEFT JOIN WAREHOUSE_LOCATION_CLASS WLC ON WL.WarehouseLocationClassID=WLC.ID AND WLC.Name NOT IN (Consignment,Subcontracting) <br>where WL.Warehouse=RS.FromWarehouse <br>AND SI2.QuantityOnHand &gt; 0 <br>AND SI2.ProductID=RSC.ProductID <br>AND CC.Name IN (UC, UCX, Virtual) <br>AND WL.WarehouseLocationType = 2 -- Warehouse Location Type = Available <br>AND SI2.InventoryStatus=1 <br>AND WL.ID!=@ToLocationID <br>--AND WLC.Name NOT IN (Consignment,Subcontracting) <br>order by --C.createdon --Commented for CHG00005652 <br>SI2.CreatedOn --CHG00005652 <br><br>) <br><br>END <br>AS Location <br><br>FROM <br>REPLENISH_STRATEGY RS <br>JOIN REPLENISH_STRATEGY_CONTENT RSC ON RSC.ProductID=ProductID <br>WHERE <br>RS.ToLocationID=@ToLocationID <br>AND RSC.ProductID=@ProductID <br>AND RS.Status = 3 /*Added for CHG00006976*/ <br><br>)<br>Severity: CRITICAL<br>Details: &quot;MCU MSSQL Server&quot;:&quot;Expensive Queries&quot; changed to CRITICAL (3193292) for set @LocationOut=( <br><br><br>SELECT DISTINCT TOP 1 <br>CASE <br>WHEN RS.FromLocationID IS NOT NULL THEN(Select Distinct WL.location from inventory2 SI2 <br>join WAREHOUSE_LOCATION WL ON SI2.WarehouseLocationId=WL.ID <br>LEFT JOIN WAREHOUSE_LOCATION_CLASS WLC ON WL.WarehouseLocationClassID=WLC.ID AND WLC.Name NOT IN (Consignment,Subcontracting) <br>where WL.ID=RS.FromLocationID <br>AND SI2.QuantityOnHand &gt; 0 <br>AND SI2.ProductID=RSC.ProductID <br>AND SI2.InventoryStatus=1 <br>-- AND WLC.Name NOT IN (Consignment,Subcontracting) <br>AND WL.WarehouseLocationType = 2 <br>AND WL.ID!=@ToLocationID) -- Warehouse Location Type = Available <br><br>WHEN RS.FromLocationID IS NULL AND RS.FromZone IS NOT NULL <br>THEN (select Top 1 WL.Location FROM INVENTORY2 SI2 <br>JOIN WAREHOUSE_LOCATION WL ON SI2.WarehouseLocationID = WL.ID <br>JOIN CONTAINER C ON C.WarehouseLocationID = WL.ID <br>JOIN CONTAINER_CLASS CC ON C.ContainerClassID = CC.ID <br>left JOIN WAREHOUSE_LOCATION_CLASS WLC ON WL.WarehouseLocationClassID=WLC.ID AND WLC.Name NOT IN (Consignment,Subcontracting) <br>where WL.Zone=RS.FromZone <br>AND SI2.QuantityOnHand &gt; 0 <br>AND SI2.ProductID=RSC.ProductID <br>AND CC.Name IN (UC, UCX, Virtual) <br>AND WL.WarehouseLocationType = 2 -- Warehouse Location Type = Available <br>AND SI2.InventoryStatus=1 <br>--AND WLC.Name NOT IN (Consignment,Subcontracting) <br>AND WL.ID!=@ToLocationID <br>order by --C.createdon --Commented for CHG00005652 <br>SI2.CreatedOn --CHG00005652 <br>) <br><br>WHEN FromLocationID IS NULL AND FromZone IS NULL AND FromWarehouse IS NOT NULL <br>THEN (select top 1 WL.Location FROM INVENTORY2 SI2 <br>JOIN WAREHOUSE_LOCATION WL ON SI2.WarehouseLocationID = WL.ID <br>JOIN CONTAINER C ON C.WarehouseLocationID = WL.ID <br>JOIN CONTAINER_CLASS CC ON C.ContainerClassID = CC.ID <br>LEFT JOIN WAREHOUSE_LOCATION_CLASS WLC ON WL.WarehouseLocationClassID=WLC.ID AND WLC.Name NOT IN (Consignment,Subcontracting) <br>where WL.Warehouse=RS.FromWarehouse <br>AND SI2.QuantityOnHand &gt; 0 <br>AND SI2.ProductID=RSC.ProductID <br>AND CC.Name IN (UC, UCX, Virtual) <br>AND WL.WarehouseLocationType = 2 -- Warehouse Location Type = Available <br>AND SI2.InventoryStatus=1 <br>AND WL.ID!=@ToLocationID <br>--AND WLC.Name NOT IN (Consignment,Subcontracting) <br>order by --C.createdon --Commented for CHG00005652 <br>SI2.CreatedOn --CHG00005652 <br><br>) <br><br>END <br>AS Location <br><br>FROM <br>REPLENISH_STRATEGY RS <br>JOIN REPLENISH_STRATEGY_CONTENT RSC ON RSC.ProductID=ProductID <br>WHERE <br>RS.ToLocationID=@ToLocationID <br>AND RSC.ProductID=@ProductID <br>AND RS.Status = 3 /*Added for CHG00006976*/ <br><br>) at 1:20 PM UTC on 01/05/2026<br>Episode ID : ad01d3de-58ca-41ca-ac60-d7b9dd88918c<br><br>View in Splunk ITSI: https://itsi-kone.splunkcloud.com/en-US/app/itsi/itsi_event_management</div><div style=\"margin-top:10px; border-top:1px solid #c3cbd4\"></div><p style=\"margin:20px; font-size:11px; color:#999\">If you believe youve received this email in error, please see your Splunk administrator.<br><br>splunk&gt;</p></div></body></html> ",
